import { Link } from "react-router-dom";
import productsData from "../data/ProductData";

const PopularProducts = () => {
  if (!productsData || productsData.length === 0) {
    return <h2 style={{ textAlign: "center" }}>⚠ No products found</h2>;
  }

  const popularItems = productsData.slice(0, 8);

  return (
    <section style={{ padding: "40px" }}>
      {/* Popular Products */}
      <h2 style={{ textAlign: "center", marginBottom: "30px" }}>
        Popular Products
      </h2>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(4, 1fr)",
          gap: "25px",
          maxWidth: "1200px",
          margin: "0 auto",
        }}
      >
        {popularItems.map((item) => (
          <div key={item.id} style={{ textAlign: "left" }}>
            {/* Image box */}
            <Link to={'/product/${item.id}'}>
              <div
                style={{
                  border: "1px solid #ddd",
                  padding: "29px",
                  background: "#f1f1f6ff",
                  height: "150px",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                }}
              >
                <img
                  src={item.image}
                  alt={item.name}
                  style={{
                    maxWidth: "100%",
                    maxHeight: "180px",
                    objectFit: "contain",
                  }}
                />
              </div>
            </Link>

            {/* Product details */}
            <h3
              style={{
                fontSize: "14px",
                margin: "10px 0 5px",
                fontFamily: "'Poppins', sans-serif",
              }}
            >
              {item.name}
            </h3>
            <p style={{ fontWeight: "bold", margin: "5px 0" }}>₹{item.price}</p>

            {/* ✅ Ratings (stars + number) */}
            <div
              style={{
                display: "flex",
                justifyContent: "left",
                alignItems: "center",
                gap: "5px",
                marginTop: "5px",
              }}
            >
              <span style={{ color: "#ee6b19ff", fontSize: "10px" }}>⭐⭐⭐⭐⭐</span>
              <span style={{ fontSize: "13px", color: "#555" }}>
                {item.rating}
              </span>
            </div>

            <Link to={'/product/${item.id}'}>
              <button
                style={{
                  marginTop: "8px",
                  padding: "8px 15px",
                  border: "none",
                  borderRadius: "6px",
                  background: "#ff6d0cff",
                  color: "#fff",
                  cursor: "pointer",
                }}
              >
                Buy Now
              </button>
            </Link>
          </div>
        ))}
      </div>

      {/* 🎮 Gaming Banner */}
      {/* 🎮 Gaming Banner */}
<section
  style={{
    marginTop: "60px",
    padding: "70px 30px",       // more vertical (60px), less horizontal (20px)
    borderRadius: "18px",
    background: "#cad6ecff",
    display: "flex",
    justifyContent: "center",   // center content
    alignItems: "center",
    flexWrap: "wrap",
    gap: "20px",
    maxWidth: "1200px",          // reduce horizontal size
    marginLeft: "auto",
    marginRight: "auto",        // centers the whole banner
  }}
>
  <img
    src="/images/product/jbl.png"
    alt="Gaming Speaker"
    style={{ maxWidth: "180px" }}
  />

  <div style={{ textAlign: "center", flex: "1", minWidth: "250px" }}>
    <h2 style={{ fontSize: "26px", fontWeight: "600" }}>
      Level Up Your Gaming Experience
    </h2>
    <p style={{ margin: "10px 0", color: "#555" }}>
      From immersive sound to precise controls—everything you need to win
    </p>
    <button
      style={{
        marginTop: "15px",
        padding: "14px 28px",
        border: "none",
        borderRadius: "6px",
        background: "#ff6d0cff",
        color: "#cfdbf1ff",
        fontWeight: "500",
        cursor: "pointer",
      }}
    >
      Buy now →
    </button>
  </div>

  <img
    src="/images/product/xbox-white.png"
    alt="Gaming Controller"
    style={{ maxWidth: "180px" }}
  />
</section>

      {/* 📩 Subscribe Section */}
      <section
        style={{
          marginTop: "60px",
          textAlign: "center",
          padding: "50px 20px",
          borderRadius: "12px",
          background: "#ffffffff",
          
        }}
      >
        <h2 style={{ fontSize: "26px", fontWeight: "600" }}>
          Subscribe now & get 20% off
        </h2>
        <p style={{ margin: "10px 0 25px", color: "#666" }}>
          Lorem Ipsum is simply dummy text of the printing and typesetting industry.
        </p>
        <div style={{ display: "flex", justifyContent: "center" }}>
          <input
            type="email"
            placeholder="Enter your email id"
            style={{
              padding: "12px",
              width: "280px",
              borderRadius: "6px 0 0 6px",
              border: "1px solid #ddd",
              outline: "none",
            }}
          />
          <button
            style={{
              padding: "12px 20px",
              border: "none",
              borderRadius: "0 6px 6px 0",
              background: "#ff6d0cff",
              color: "#fff",
              cursor: "pointer",
            }}
          >
            Subscribe
          </button>
        </div>
      </section>
    </section>
  );
};

export default PopularProducts;
